import SidebarIcon from "./SidebarIcon";

import classes from "./ServerList.module.css";

const ServerList = () => {
  return (
    <nav>
      <div className={classes["server-list"]}>
        <SidebarIcon id="1"></SidebarIcon>
        <SidebarIcon id="2"></SidebarIcon>
        <SidebarIcon id="3"></SidebarIcon>
      </div>
    </nav>
  );
};

export default ServerList;
